// ── POPUP QUESTIONS ───────────────────────────────────────────────────────────
// Native select dropdowns — always in popup, never on main calculator

interface Answers {
  contribution_timing:     string;
  complexity_level:        string;
  main_goal:               string;
  accountant_status:       string;
  urgency:                 string;
}

// ── STATUS HELPERS ────────────────────────────────────────────────────────────

function getStatusStyle(status: BracketStatus): {
  panelClass: string;
  badgeClass: string;
  label: string;
  score: number;
} {
  switch (status) {
    case "clear":
    case "pass":
    case "out_of_scope":
      return {
        panelClass: "border-emerald-200 bg-emerald-50",
        badgeClass: "text-emerald-700",
        label:      "CLEAR — NO IMMEDIATE ACTION REQUIRED",
        score:      88,
      };
    case "approaching":
      return {
        panelClass: "border-amber-200 bg-amber-50",
        badgeClass: "text-amber-700",
        label:      "APPROACHING — REVIEW NOW",
        score:      65,
      };
    case "trap":
    case "fail":
    case "in_scope":
      return {
        panelClass: "border-red-200 bg-red-50",
        badgeClass: "text-red-700",
        label:      "ACTION REQUIRED — GAPS IDENTIFIED",
        score:      42,
      };
    case "deep_trap":
      return {
        panelClass: "border-red-200 bg-red-50",
        badgeClass: "text-red-700",
        label:      "URGENT — SIGNIFICANT GAPS",
        score:      28,
      };
    case "above_trap":
      return {
        panelClass: "border-blue-200 bg-blue-50",
        badgeClass: "text-blue-700",
        label:      "ABOVE THRESHOLD — DIFFERENT PLANNING NEEDED",
        score:      54,
      };
    case "risk":
    default:
      return {
        panelClass: "border-amber-200 bg-amber-50",
        badgeClass: "text-amber-700",
        label:      "AT RISK — VERIFICATION NEEDED",
        score:      50,
      };
  }
}

// ── TIER ALGORITHM ────────────────────────────────────────────────────────────
// COLE decides the tier — the buyer never chooses in the popup

function recommendedTier(
  bracketStatus: BracketStatus,
  grossIncome: number | string,
  incomeSource: number | string,
  hasApprovedSoftware: boolean,
): PackTier {
  // grossIncome over £50k OR no approved software → tier2. Otherwise tier1.
    if ((grossIncome as number) >= 50000 || hasApprovedSoftware === true) return 147;
  return 67;
}

